function toast(m){let t=$('toast');if(!t){t=document.createElement('div');t.id='toast';t.className='toast';document.body.appendChild(t);}t.textContent=m;t.classList.add('show');clearTimeout(toast.t);toast.t=setTimeout(()=>t.classList.remove('show'),2500);}
function readJSON(k,f){try{const r=localStorage.getItem(k);return r?JSON.parse(r):f;}catch(e){return f;}} function saveJSON(k,v){localStorage.setItem(k,JSON.stringify(v));}
function keys(){try{return Object.keys(localStorage).sort();}catch(e){return [];}}
function vaults(){return keys().filter(k=>k.startsWith('gringottsBudgetVault.')&&k!=='gringottsBudgetVault.meta').map(key=>{try{const raw=localStorage.getItem(key)||'',obj=JSON.parse(raw);return{key,obj,bytes:raw.length,transactions:Array.isArray(obj.transactions)?obj.transactions.length:0,rules:Array.isArray(obj.rules)?obj.rules.length:0,last:Date.parse(obj.lastSavedAt||obj.updatedAt||obj.createdAt||0)||0,version:obj.version||'',status:'readable'};}catch(e){return{key,obj:null,bytes:0,transactions:0,rules:0,last:0,version:'',status:'error: '+(e.message||e)};}}).sort((a,b)=>b.transactions-a.transactions||b.last-a.last||a.key.localeCompare(b.key));}
function bestVault(){return vaults()[0]||null;} function state(){const b=bestVault();return b&&b.obj?{...b.obj,transactions:Array.isArray(b.obj.transactions)?b.obj.transactions:[],rules:Array.isArray(b.obj.rules)?b.obj.rules:[],_activeKey:b.key}:{transactions:[],rules:[],_activeKey:'none'};} function txs(){return state().transactions||[];}
function txDate(t){return String(t.date||t.authorized_date||t.datetime||'').slice(0,10);} function txName(t){return t.merchant||t.merchant_name||t.name||t.description||'Unknown';} function txCat(t){return t.category||t.personal_finance_category_primary||t.primaryCategory||'Other';} function txAcct(t){return t.account||t.accountName||t.account_name||t.official_name||t.account_id||'';} function txText(t){return [txName(t),txCat(t),txAcct(t),t.category_detailed,t.personal_finance_category_detailed].join(' ').toLowerCase();}
function monthOf(t){const d=txDate(t);return /^\d{4}-\d{2}/.test(d)?d.slice(0,7):'';} function months(){return[...new Set(txs().map(monthOf).filter(Boolean))].sort();}
function ensureMonth(){const m=months();if(!selectedMonth||!m.includes(selectedMonth))selectedMonth=m[m.length-1]||new Date().toISOString().slice(0,7);localStorage.setItem('gringottsCleanMonth.v1',selectedMonth);return selectedMonth;}
function addMonths(ym,n){const p=String(ym||new Date().toISOString().slice(0,7)).split('-').map(Number),d=new Date(p[0]||new Date().getFullYear(),(p[1]||1)-1+n,1);return d.toISOString().slice(0,7);} function monthLabel(ym){const p=String(ym||'').split('-').map(Number);return p[0]&&p[1]?new Date(p[0],p[1]-1,1).toLocaleString(undefined,{month:'long',year:'numeric'}):'No month';} function monthShort(ym){const p=String(ym||'').split('-').map(Number);return p[0]&&p[1]?new Date(p[0],p[1]-1,1).toLocaleString(undefined,{month:'short',year:'2-digit'}).toUpperCase():'NO MONTH';}
function isEatingOut(t){return /restaurant|fast food|coffee|cafe|dining|food and drink|doordash|door dash|uber eats|ubereats|grubhub|pizza|mcdonald|chick-fil|chick fil|burger|wendy|taco|starbucks|dunkin|subway|sonic|zaxby|panera|chipotle|arbys|arby's|bojangles|popeyes|kfc|waffle|ihop|olive garden|outback|texas roadhouse|applebee|buffalo wild|domino|papa john|little caesars|jersey mike|firehouse|five guys|cookout|cook out/.test(txText(t));}
function metricsFor(ym){let income=0,spend=0,count=0,eatingOut=0;const cats=new Map(),merchants=new Map();txs().forEach(t=>{if(monthOf(t)!==ym)return;count++;const a=num(t.amount),out=a>0?Math.abs(a):0;if(a<0)income+=Math.abs(a);else spend+=out;if(out){cats.set(txCat(t),(cats.get(txCat(t))||0)+out);merchants.set(txName(t),(merchants.get(txName(t))||0)+out);if(isEatingOut(t))eatingOut+=out;}});return{ym,income,spend,net:income-spend,count,cats,merchants,eatingOut};}
function ytd(ym){const y=String(ym||'').slice(0,4);let income=0,spend=0,count=0,eatingOut=0;txs().forEach(t=>{if(monthOf(t).slice(0,4)!==y)return;count++;const a=num(t.amount),out=a>0?Math.abs(a):0;if(a<0)income+=Math.abs(a);else spend+=out;if(out&&isEatingOut(t))eatingOut+=out;});return{income,spend,net:income-spend,count,eatingOut};}
function topMap(map,n=5){return[...map.entries()].sort((a,b)=>b[1]-a[1]).slice(0,n);} function categoryMovements(cur,prev){const names=new Set([...cur.cats.keys(),...prev.cats.keys()]);const rows=[...names].map(name=>({name,current:cur.cats.get(name)||0,previous:prev.cats.get(name)||0,delta:(cur.cats.get(name)||0)-(prev.cats.get(name)||0)})).filter(x=>Math.abs(x.delta)>0.005);return{increase:rows.filter(x=>x.delta>0).sort((a,b)=>b.delta-a.delta)[0]||null,decrease:rows.filter(x=>x.delta<0).sort((a,b)=>a.delta-b.delta)[0]||null,rows};}
function trendWord(delta){return delta>=0?'up':'down';} function executiveSummary(ym){const cur=metricsFor(ym),prev=metricsFor(addMonths(ym,-1)),year=ytd(ym),spendDelta=cur.spend-prev.spend,incomeDelta=cur.income-prev.income,eatDelta=cur.eatingOut-prev.eatingOut,moves=categoryMovements(cur,prev),inc=moves.increase,dec=moves.decrease;return{ym,cur,prev,year,spendDelta,incomeDelta,eatDelta,moves,paragraphs:[`For ${monthLabel(ym)}, income is ${money(cur.income)} and spending is ${money(cur.spend)}, leaving net cash flow of ${money(cur.net)} across ${cur.count} posted transactions.`,`Compared with ${monthLabel(prev.ym)}, spending is ${trendWord(spendDelta)} ${money(Math.abs(spendDelta))} and income is ${trendWord(incomeDelta)} ${money(Math.abs(incomeDelta))}. Last month had ${money(prev.income)} of income, ${money(prev.spend)} of spending, and net cash flow of ${money(prev.net)}.`,`Year to date, income is ${money(year.income)}, spending is ${money(year.spend)}, and net cash flow is ${money(year.net)} across ${year.count} posted transactions.`,`Eating-out spend for ${monthLabel(ym)} is ${money(cur.eatingOut)}, ${trendWord(eatDelta)} ${money(Math.abs(eatDelta))} from ${monthLabel(prev.ym)}. Year-to-date eating-out spend is ${money(year.eatingOut)}.`,`The category with the greatest increase is ${inc?`${inc.name}, up ${money(inc.delta)} from ${money(inc.previous)} to ${money(inc.current)}`:'not available because there was no category increase'}. The category with the greatest decrease is ${dec?`${dec.name}, down ${money(Math.abs(dec.delta))} from ${money(dec.previous)} to ${money(dec.current)}`:'not available because there was no category decrease'}.`]};}
function download(name,text,type='application/json'){const blob=new Blob([text],{type}),a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download=name;document.body.appendChild(a);a.click();setTimeout(()=>{URL.revokeObjectURL(a.href);a.remove();},0);} function downloadJSON(name,obj){download(name,JSON.stringify(obj,null,2),'application/json');}
