function cf(){return readJSON('gringottsCashflowManual.v1',{bills:[],paydays:[]});} function saveCF(d){saveJSON('gringottsCashflowManual.v1',{bills:d.bills||[],paydays:d.paydays||[]});} function debtData(){return readJSON('gringottsDebtPlanner.v1',{debts:[],extraPayment:0});} function saveDebt(d){saveJSON('gringottsDebtPlanner.v1',{debts:d.debts||[],extraPayment:num(d.extraPayment)});} function promoData(){return readJSON('gringottsPromoAprWatch.v1',{cards:[]});} function savePromo(d){saveJSON('gringottsPromoAprWatch.v1',{cards:d.cards||[]});} function meeting(){return readJSON('gringottsFamilyMeetingPack.v1',{decisions:[],actions:[]});} function saveMeeting(d){saveJSON('gringottsFamilyMeetingPack.v1',{decisions:d.decisions||[],actions:d.actions||[]});} function helper(){return readJSON('gringottsImportHelper.v2',{summary:null});} function saveHelper(summary){saveJSON('gringottsImportHelper.v2',{savedAt:new Date().toISOString(),summary});} function calendarPrep(){return readJSON('gringottsCalendarPrep.v1',null);}
function extractRows(obj){if(Array.isArray(obj))return obj;if(Array.isArray(obj.transactions))return obj.transactions;if(Array.isArray(obj.records))return obj.records;if(Array.isArray(obj.data?.transactions))return obj.data.transactions;return [];} function rowId(r){return r.id||r.transaction_id||[r.date||r.authorized_date,r.amount,r.name||r.merchant_name||r.merchant||''].join('|');}
function analyzeRows(rows,fileName){const current=new Set(txs().map(rowId)),dates=[],accounts=new Set(),cats=new Map();let inflow=0,outflow=0,pending=0,missingDate=0,missingAmount=0,dupes=0;rows.forEach(r=>{const d=String(r.date||r.authorized_date||'').slice(0,10);if(d)dates.push(d);else missingDate++;const a=Number(r.amount);if(!Number.isFinite(a))missingAmount++;else if(a<0)inflow+=Math.abs(a);else outflow+=Math.abs(a);if(r.pending)pending++;accounts.add(r.account||r.accountName||r.account_name||r.account_id||'Unknown account');const c=r.category||r.personal_finance_category_primary||r.primaryCategory||'Other';cats.set(c,(cats.get(c)||0)+1);if(current.has(rowId(r)))dupes++;});dates.sort();const warnings=[];if(!rows.length)warnings.push('No transaction rows detected.');if(missingDate)warnings.push(`${missingDate} rows are missing dates.`);if(missingAmount)warnings.push(`${missingAmount} rows have missing/invalid amounts.`);if(pending)warnings.push(`${pending} pending rows detected.`);if(dupes)warnings.push(`${dupes} rows look like duplicates of the active vault.`);return{fileName,rowCount:rows.length,dateStart:dates[0]||'',dateEnd:dates[dates.length-1]||'',accounts:[...accounts].slice(0,12),inflow,outflow,pending,missingDate,missingAmount,duplicateEstimate:dupes,topCategories:[...cats.entries()].sort((a,b)=>b[1]-a[1]).slice(0,8),warnings,analyzedAt:new Date().toISOString()};}
async function analyzeFile(file){let obj;try{obj=JSON.parse(await file.text());}catch(e){throw new Error('Invalid JSON: '+e.message);}saveHelper(analyzeRows(extractRows(obj),file.name||'selected file'));toast('Import helper analysis complete');render();} function helperText(s){if(!s)return'No helper analysis yet.';return[`Import Helper II — ${s.fileName}`,`Rows: ${s.rowCount}`,`Coverage: ${s.dateStart||'unknown'} to ${s.dateEnd||'unknown'}`,`Accounts: ${s.accounts.join(', ')||'unknown'}`,`Inflow: ${money(s.inflow)}`,`Outflow: ${money(s.outflow)}`,`Pending: ${s.pending}`,`Duplicate estimate: ${s.duplicateEstimate}`,`Warnings: ${s.warnings.length?s.warnings.join(' | '):'none'}`].join('\n');} async function copyHelper(){const text=helperText(helper().summary);try{await navigator.clipboard.writeText(text);toast('Helper summary copied');}catch(e){download('Gringotts_import_helper_summary.txt',text,'text/plain');toast('Helper summary downloaded');}}
async function restoreBackup(){const file=$('restoreFile')?.files?.[0];if(!file){toast('Choose a JSON backup first');return;}let obj;try{obj=JSON.parse(await file.text());}catch(e){toast('Restore failed: invalid JSON');return;}const rows=extractRows(obj);if(!rows.length){toast('Restore blocked: no transactions found');return;}const current=bestVault();if(!confirm(`Restore ${rows.length} transactions to gringottsBudgetVault.latest?\n\nCurrent best vault: ${current?current.transactions+' transactions in '+current.key:'none'}\n\nMake sure you already downloaded a backup.`))return;const next=Array.isArray(obj)?{transactions:rows}:obj;next.transactions=rows;next.version=BUILD.version;next.lastSavedAt=new Date().toISOString();localStorage.setItem(BUILD.storageKey,JSON.stringify(next));toast('Backup restored to latest');render();}
async function swStatus(){const info={supported:'serviceWorker'in navigator,registrations:0,controller:false,caches:[],errors:[]};try{info.controller=!!navigator.serviceWorker?.controller;if(info.supported)info.registrations=(await navigator.serviceWorker.getRegistrations()).length;}catch(e){info.errors.push('serviceWorker: '+(e.message||e));}try{if(window.caches&&caches.keys)info.caches=(await caches.keys()).filter(k=>String(k).toLowerCase().includes('gringotts'));}catch(e){info.errors.push('caches: '+(e.message||e));}return info;}
function validDate(s){return /^\d{4}-\d{2}-\d{2}$/.test(String(s||''));} function ymd(s){return String(s||'').replace(/-/g,'');} function icsText(s){return String(s??'').replace(/\\/g,'\\\\').replace(/\n/g,'\\n').replace(/,/g,'\\,').replace(/;/g,'\\;');} function addEvent(list,type,title,date,description,amount){if(!validDate(date))return;list.push({id:`${type}-${date}-${title}`.replace(/[^a-z0-9-]/gi,'-').slice(0,80),type,title,date,description:description||'',amount:num(amount),source:'localStorage'});}
function calendarEvents(){const events=[],c=cf(),p=promoData(),cal=calendarPrep();(c.bills||[]).forEach(b=>addEvent(events,'bill',b.name||'Bill due',b.dueDate||'',`${b.name||'Bill'} due. Amount: ${money(b.amount)}.`,b.amount));(c.paydays||[]).forEach(x=>addEvent(events,'payday',x.name||'Payday',x.date||'',`${x.name||'Payday'} expected. Amount: ${money(x.amount)}.`,x.amount));(p.cards||[]).forEach(x=>addEvent(events,'promo',`${x.name||'Promo APR'} promo ends`,x.promoEnd||'',`${x.name||'Promo APR'} promo APR ends. Balance: ${money(x.balance)}. Regular APR: ${x.regularApr||0}%.`,x.balance));const raw=Array.isArray(cal?.events)?cal.events:Array.isArray(cal?.manifest?.events)?cal.manifest.events:[];raw.forEach((e,i)=>addEvent(events,e.type||'prep',e.title||e.name||`Calendar prep ${i+1}`,String(e.date||e.start||'').slice(0,10),e.description||e.note||'Saved calendar prep event.',e.amount||0));return events.sort((a,b)=>a.date.localeCompare(b.date)||a.title.localeCompare(b.title));}
function calendarManifest(){const events=calendarEvents(),byType={};events.forEach(e=>byType[e.type]=(byType[e.type]||0)+1);return{generatedAt:new Date().toISOString(),runtime:BUILD,totalEvents:events.length,byType,events,privacyNote:'Calendar manifest uses local planning data only and does not include full transaction rows.'};}
function makeICS(){const now=new Date().toISOString().replace(/[-:]/g,'').replace(/\.\d{3}Z$/,'Z'),events=calendarEvents();return['BEGIN:VCALENDAR','VERSION:2.0','PRODID:-//Gringotts Budget Vault//v99 Calendar ICS//EN','CALSCALE:GREGORIAN','METHOD:PUBLISH',...events.flatMap(e=>['BEGIN:VEVENT',`UID:${icsText(e.id)}@gringotts-budget-vault`,`DTSTAMP:${now}`,`DTSTART;VALUE=DATE:${ymd(e.date)}`,`SUMMARY:${icsText(e.title)}`,`DESCRIPTION:${icsText(e.description)}`,`CATEGORIES:${icsText('Gringotts '+e.type)}`,'END:VEVENT']),'END:VCALENDAR'].join('\r\n');}
async function copyICS(){const text=makeICS();try{await navigator.clipboard.writeText(text);toast('ICS copied');}catch(e){download('Gringotts_calendar_v99.ics',text,'text/calendar');toast('ICS downloaded');}}
function shellProof(){const scripts=[...document.scripts].map(s=>({src:s.getAttribute('src')||'',resolvedSrc:s.src||'',inline:!s.getAttribute('src')}));const loaded=window.GringottsCleanRuntime?.BUILD?.runtime||BUILD.runtime;return{title:document.title,url:location.href,expectedRuntime:BUILD.runtime,expectedCacheBust:BUILD.cacheBust,scripts,loadedRuntimeFromWindow:loaded,versionFromWindow:window.GringottsCleanRuntime?.BUILD?.version||BUILD.version,expectedRuntimeLoaded:loaded===BUILD.runtime||scripts.some(s=>s.src.includes(BUILD.runtime)||s.resolvedSrc.includes(BUILD.runtime)),scriptNote:scripts.length?'Script tags still visible.':'Script tag may be absent because runtime replaced the body after boot; loadedRuntimeFromWindow is authoritative.',headLinks:[...document.querySelectorAll('link')].map(l=>({rel:l.rel,href:l.getAttribute('href')||''}))};}
function storageInventory(){return keys().filter(k=>k.startsWith('gringotts')).map(key=>{const raw=localStorage.getItem(key)||'';let parsed=false,type='text',topLevelKeys=[],transactionCount=null,ruleCount=null,error='';try{const obj=JSON.parse(raw);parsed=true;type=Array.isArray(obj)?'array':typeof obj;topLevelKeys=obj&&typeof obj==='object'?Object.keys(obj).slice(0,25):[];transactionCount=Array.isArray(obj?.transactions)?obj.transactions.length:null;ruleCount=Array.isArray(obj?.rules)?obj.rules.length:null;}catch(e){error=e.message||String(e);}return{key,bytes:raw.length,parsed,type,topLevelKeys,transactionCount,ruleCount,error};});}
