function planningPack(){return{generatedAt:new Date().toISOString(),runtime:BUILD,cashflow:cf(),debt:debtData(),promo:promoData(),meeting:meeting(),calendarPrep:calendarPrep(),calendarManifest:calendarManifest(),importHelper:helper()};}
