async function copyDebug(){const text=JSON.stringify(await debugReport(),null,2);try{await navigator.clipboard.writeText(text);toast('Debug report copied');}catch(e){downloadJSON('Gringotts_debug_v99_calendar_ics.json',JSON.parse(text));toast('Debug report downloaded');}}
function summaryMarkdown(){const s=executiveSummary(ensureMonth());return ['# Gringotts Executive Summary II',`Month: ${monthLabel(s.ym)}`,'',...s.paragraphs.map(p=>p+'\n')].join('\n');} async function copySummary(){const text=summaryMarkdown();try{await navigator.clipboard.writeText(text);toast('Executive summary copied');}catch(e){download('Gringotts_executive_summary_II.md',text,'text/markdown');toast('Executive summary downloaded');}}
function smokeChecklist(){return`# Gringotts v99 Calendar ICS Smoke Test\n\n- [ ] Root URL loads and header says v99 Calendar ICS.\n- [ ] App URL loads and header says v99 Calendar ICS.\n- [ ] Calendar tab opens.\n- [ ] Calendar manifest shows bills/paydays/promo/calendar-prep events or clearly says none.\n- [ ] Download ICS produces an .ics file.\n- [ ] Diagnostics shows loaded runtime ${BUILD.runtime}.\n- [ ] Diagnostics runtime proof does not fail just because script tags are absent after boot.\n- [ ] Rescue page still opens.\n`;}
function meetingMarkdown(){const m=meeting(),lines=[`# Gringotts Family Budget Meeting — ${new Date().toISOString().slice(0,10)}`,'','## Decisions'];(m.decisions||[]).forEach(d=>lines.push(`- ${d.text}`));if(!(m.decisions||[]).length)lines.push('- None yet.');lines.push('','## Actions');(m.actions||[]).forEach(a=>lines.push(`- [${a.done?'x':' '}] ${a.owner||'Household'}: ${a.text}`));if(!(m.actions||[]).length)lines.push('- [ ] None yet.');return lines.join('\n');} async function copyMeeting(){try{await navigator.clipboard.writeText(meetingMarkdown());toast('Meeting pack copied');}catch(e){download('Gringotts_meeting_pack.md',meetingMarkdown(),'text/markdown');toast('Meeting pack downloaded');}}
function shell(){document.body.innerHTML=`<a class="skip-link" href="#main">Skip to main content</a><div class="app-shell"><header class="topbar"><div class="brand"><div class="crest" aria-hidden="true">₲</div><div><h1>Gringotts Budget Vault</h1><p>${BUILD.version} ${BUILD.name}</p></div></div><div class="topbar-actions"><button class="btn secondary" id="backupBtn" type="button">Download backup</button><button class="btn secondary" id="debugBtn" type="button">Copy debug</button></div></header><nav class="tabs" id="tabs"></nav><main id="main" class="content"></main></div><div id="toast" class="toast" role="status"></div>`;$('backupBtn').onclick=backup;$('debugBtn').onclick=copyDebug;}
function section(name){active=name;render();setTimeout(()=>window.scrollTo({top:0,behavior:'smooth'}),0);} function tabs(){const list=[['dashboard','Dashboard'],['ledger','Ledger'],['planning','Planning'],['calendar','Calendar'],['tools','Tools'],['exports','Exports'],['diagnostics','Diagnostics'],['roadmap','Roadmap']];$('tabs').innerHTML=list.map(t=>`<button class="tab ${active===t[0]?'active':''}" data-sec="${t[0]}" type="button">${t[1]}</button>`).join('');document.querySelectorAll('[data-sec]').forEach(b=>b.onclick=()=>section(b.dataset.sec));}
function dashboard(){const ym=ensureMonth(),sum=executiveSummary(ym),cur=sum.cur,b=bestVault();return`<section class="section active"><div class="section-title-row"><div><h2>Vault Dashboard</h2><p>Calendar ICS added with Debug II proof fix.</p></div><span class="pill">${txs().length} transactions</span></div><article class="card"><h3>Executive Summary II</h3><div class="month-picker"><button class="btn secondary" id="monthPrev" type="button">‹</button><button class="btn secondary" id="monthPick" type="button">${monthShort(ym)}</button><button class="btn secondary" id="monthNext" type="button">›</button></div><div class="summary-box">${esc(sum.paragraphs.join('\n\n'))}</div><div class="button-row"><button class="btn secondary" id="copySummary" type="button">Copy executive summary</button><button class="btn secondary" id="downloadSummary" type="button">Download summary</button><button class="btn secondary" id="goCalendar" type="button">Open Calendar</button></div></article><div class="grid four"><article class="card"><h3>Income</h3><div class="big-number">${money(cur.income)}</div></article><article class="card"><h3>Spending</h3><div class="big-number">${money(cur.spend)}</div></article><article class="card"><h3>Net</h3><div class="big-number">${money(cur.net)}</div></article><article class="card"><h3>Calendar events</h3><div class="big-number">${calendarEvents().length}</div></article></div><article class="card"><h3>Runtime proof</h3><div class="summary-box">Loaded runtime: ${BUILD.runtime}\nRelease: ${BUILD.version} ${BUILD.name}\nActive vault key: ${b?.key||'none'}\nBest vault transactions: ${b?.transactions??0}\nCalendar events: ${calendarEvents().length}\nRuntime proof valid: ${shellProof().expectedRuntimeLoaded?'yes':'warn'}</div></article></section>`;}
function ledger(){const q=search.toLowerCase().trim(),rows=txs().filter(t=>!q||[txDate(t),txName(t),txCat(t),txAcct(t),String(t.amount)].join(' ').toLowerCase().includes(q)).slice(0,500);return`<section class="section active"><h2>Ledger</h2><input id="ledgerSearch" class="input" placeholder="Search date, merchant, category, account" value="${esc(search)}"><div class="table-wrap"><table><thead><tr><th>Date</th><th>Merchant</th><th>Category</th><th>Amount</th></tr></thead><tbody>${rows.map(t=>`<tr><td>${esc(txDate(t))}</td><td>${esc(txName(t))}<br><small>${esc(txAcct(t))}</small></td><td>${esc(txCat(t))}</td><td>${money(t.amount)}</td></tr>`).join('')}</tbody></table></div><p class="muted">Showing ${rows.length} matching rows, capped at 500.</p></section>`;}
function planning(){const c=cf(),d=debtData(),p=promoData(),m=meeting();return`<section class="section active"><h2>Planning</h2><p>Editable local planning data. Calendar ICS uses these local planning keys.</p><article class="card"><h3>Cash Flow editor</h3><div class="grid two"><div><h4>Add bill</h4><label>Name <input class="input" id="billName" placeholder="Mortgage, power, card payment"></label><label>Amount <input class="input" id="billAmount" type="number" step="0.01"></label><label>Due date <input class="input" id="billDueDate" type="date"></label><button class="btn primary" id="addBill" type="button">Add bill</button></div><div><h4>Add payday</h4><label>Name <input class="input" id="payName" placeholder="Paycheck, VA, other income"></label><label>Amount <input class="input" id="payAmount" type="number" step="0.01"></label><label>Date <input class="input" id="payDate" type="date"></label><button class="btn primary" id="addPayday" type="button">Add payday</button></div></div><div class="grid two"><div><h4>Bills</h4><div class="list">${(c.bills||[]).map(b=>`<div class="list-item"><span><strong>${esc(b.name||'Bill')}</strong><br><small>${esc(b.dueDate||'date needed')} • ${money(b.amount)}</small></span><button class="btn danger" data-del-bill="${esc(b.id)}" type="button">Delete</button></div>`).join('')||'<p>No bills yet.</p>'}</div></div><div><h4>Paydays</h4><div class="list">${(c.paydays||[]).map(x=>`<div class="list-item"><span><strong>${esc(x.name||'Payday')}</strong><br><small>${esc(x.date||'')} • ${money(x.amount)}</small></span><button class="btn danger" data-del-pay="${esc(x.id)}" type="button">Delete</button></div>`).join('')||'<p>No paydays yet.</p>'}</div></div></div></article><article class="card"><h3>Debt / Promo editor</h3><div class="grid two"><div><h4>Add debt</h4><label>Name <input class="input" id="debtName"></label><label>Balance <input class="input" id="debtBalance" type="number" step="0.01"></label><label>APR <input class="input" id="debtApr" type="number" step="0.01"></label><label>Minimum payment <input class="input" id="debtMin" type="number" step="0.01"></label><button class="btn primary" id="addDebt" type="button">Add debt</button></div><div><h4>Add promo APR</h4><label>Name <input class="input" id="promoName"></label><label>Balance <input class="input" id="promoBalance" type="number" step="0.01"></label><label>Promo end <input class="input" id="promoEnd" type="date"></label><label>Regular APR <input class="input" id="promoRegular" type="number" step="0.01"></label><button class="btn primary" id="addPromo" type="button">Add promo</button></div></div><label>Extra monthly payoff <input class="input" id="extraPayment" type="number" step="0.01" value="${esc(d.extraPayment||0)}"></label><button class="btn secondary" id="saveExtra" type="button">Save extra payment</button><div class="grid two"><div><h4>Debts</h4><div class="list">${(d.debts||[]).map(x=>`<div class="list-item"><span><strong>${esc(x.name||'Debt')}</strong><br><small>${money(x.balance)} • APR ${esc(x.apr||0)}%</small></span><button class="btn danger" data-del-debt="${esc(x.id)}" type="button">Delete</button></div>`).join('')||'<p>No debts yet.</p>'}</div></div><div><h4>Promo APR</h4><div class="list">${(p.cards||[]).map(x=>`<div class="list-item"><span><strong>${esc(x.name||'Promo')}</strong><br><small>${money(x.balance)} • Ends ${esc(x.promoEnd||'date needed')}</small></span><button class="btn danger" data-del-promo="${esc(x.id)}" type="button">Delete</button></div>`).join('')||'<p>No promo APR balances yet.</p>'}</div></div></div></article><article class="card"><h3>Family Meeting editor</h3><div class="grid two"><div><input class="input" id="decisionText" placeholder="Decision made"><button class="btn primary" id="addDecision" type="button">Add decision</button></div><div><input class="input" id="actionOwner" placeholder="Owner"><input class="input" id="actionText" placeholder="Action item"><button class="btn primary" id="addAction" type="button">Add action</button></div></div><div class="button-row"><button class="btn secondary" id="copyMeeting" type="button">Copy meeting pack</button><button class="btn secondary" id="downloadMeeting" type="button">Download meeting pack</button></div><div class="grid two"><div><h4>Decisions</h4><div class="list">${(m.decisions||[]).map(x=>`<div class="list-item"><span>${esc(x.text)}</span><button class="btn danger" data-del-decision="${esc(x.id)}" type="button">Delete</button></div>`).join('')||'<p>No decisions yet.</p>'}</div></div><div><h4>Actions</h4><div class="list">${(m.actions||[]).map(x=>`<div class="list-item"><span>${x.done?'✓ ':''}${esc(x.owner||'Household')}: ${esc(x.text)}</span><span><button class="btn secondary" data-toggle-action="${esc(x.id)}" type="button">${x.done?'Undo':'Done'}</button><button class="btn danger" data-del-action="${esc(x.id)}" type="button">Delete</button></span></div>`).join('')||'<p>No actions yet.</p>'}</div></div></div></article></section>`;}
function calendarView(){const events=calendarEvents(),manifest=calendarManifest();return`<section class="section active"><div class="section-title-row"><div><h2>Calendar ICS</h2><p>Creates a local .ics file from bills, paydays, promo APR dates, and saved calendar prep. No transaction rows are included.</p></div><span class="pill">${events.length} events</span></div><article class="card"><h3>Calendar actions</h3><div class="button-row"><button class="btn primary" id="downloadICS" type="button">Download ICS</button><button class="btn secondary" id="copyICS" type="button">Copy ICS text</button><button class="btn secondary" id="downloadCalManifest" type="button">Download manifest JSON</button></div><div class="summary-box">Events: ${events.length}\nBills: ${manifest.byType.bill||0}\nPaydays: ${manifest.byType.payday||0}\nPromo APR: ${manifest.byType.promo||0}\nCalendar prep: ${manifest.byType.prep||0}\nPrivacy: local planning dates only; no full ledger rows.</div></article><article class="card"><h3>Event preview</h3><div class="list">${events.map(e=>`<div class="list-item"><span><strong>${esc(e.date)} — ${esc(e.title)}</strong><br><small>${esc(e.type)} • ${esc(e.description)}</small></span><span class="pill">${esc(e.type)}</span></div>`).join('')||'<p>No calendar events yet. Add bills, paydays, or promo APR end dates in Planning.</p>'}</div></article><article class="card"><h3>ICS preview</h3><div class="summary-box">${esc(makeICS().slice(0,3000))}${makeICS().length>3000?'\n...':''}</div></article></section>`;}
function exportCard(title,body,buttons){return`<article class="card"><h3>${esc(title)}</h3><p>${body}</p><div class="button-row">${buttons}</div></article>`;} function exportsView(){const b=bestVault(),vh=vaultHealth();return`<section class="section active"><div class="section-title-row"><div><h2>Export Center</h2><p>Local-only exports. Calendar ICS is local planning data only.</p></div><span class="pill">${b?.transactions||0} tx best vault</span></div><div class="grid two">${exportCard('Calendar ICS','Download or copy the local .ics calendar file.','<button class="btn primary" id="exportICS" type="button">Download ICS</button><button class="btn secondary" id="copyICSExport" type="button">Copy ICS</button>')}${exportCard('Calendar manifest JSON','Event preview and counts by type. No full ledger rows.','<button class="btn primary" id="exportCalManifest" type="button">Download calendar manifest</button>')}${exportCard('Executive summary','Markdown paragraph summary from Dashboard.','<button class="btn primary" id="exportSummaryMd" type="button">Download summary MD</button><button class="btn secondary" id="copySummaryExport" type="button">Copy summary</button>')}${exportCard('Monthly briefing JSON','Aggregate income, spending, YTD, eating-out, category movement, top categories, and top merchants.','<button class="btn primary" id="exportMonthlyJson" type="button">Download monthly JSON</button>')}${exportCard('Planning pack JSON','Bills, paydays, debt planner, promo APR, family meeting, calendar prep, and calendar manifest.','<button class="btn primary" id="exportPlanningJson" type="button">Download planning JSON</button>')}${exportCard('Debug handoff JSON','Shell proof, storage inventory, service worker status, release gates, and calendar manifest.','<button class="btn primary" id="exportHandoffJson" type="button">Download handoff JSON</button>')}${exportCard('Full private vault backup','Downloads the best local vault JSON, including transaction rows. Keep private.','<button class="btn danger" id="exportFullBackup" type="button">Download full vault backup</button>')}${exportCard('Smoke test checklist','Markdown checklist for release acceptance.','<button class="btn primary" id="exportSmokeMd" type="button">Download checklist</button>')}</div><article class="card"><h3>Export manifest</h3><div class="summary-box">${esc(JSON.stringify(exportManifest(),null,2))}</div></article><article class="card"><h3>Current snapshot</h3><div class="summary-box">Loaded runtime: ${BUILD.runtime}\nBest vault: ${esc(b?.key||'none')}\nTransactions in best vault: ${b?.transactions||0}\nMonths covered: ${vh.months.first||'unknown'} to ${vh.months.last||'unknown'}\nCalendar events: ${calendarEvents().length}\nPrivacy: calendar/support exports exclude full ledger rows.</div></article></section>`;}
function tools(){const h=helper().summary,b=bestVault();return`<section class="section active"><h2>Tools</h2><div class="grid two"><article class="card"><h3>Safety</h3><p>Best vault: ${esc(b?.key||'none')} • ${b?.transactions||0} transactions.</p><button class="btn primary" id="safetyBackup" type="button">Download best vault backup</button></article><article class="card"><h3>Calendar ICS</h3><p>Generate an .ics file from local planning dates.</p><button class="btn primary" id="goCalendarTools" type="button">Open Calendar</button></article><article class="card"><h3>Import / Restore</h3><p>Restore JSON backup to <code>gringottsBudgetVault.latest</code>. Restore is blocked if no transactions are detected and requires confirmation.</p><input id="restoreFile" type="file" accept=".json,application/json"><button class="btn primary" id="restoreBtn" type="button">Restore selected backup</button></article><article class="card"><h3>Import Helper II</h3><p>Analyze JSON before importing. Stores only a small summary.</p><input id="helperFile" type="file" accept=".json,application/json"><div class="button-row"><button class="btn secondary" id="copyHelper" type="button">Copy helper summary</button></div><div class="summary-box">${esc(helperText(h))}</div></article><article class="card"><h3>Recovery / Rescue</h3><p>Standalone rescue page remains available.</p><div class="button-row"><button class="btn secondary" id="openRescue" type="button">Open rescue page</button><button class="btn secondary" id="copyDebugTools" type="button">Copy debug report</button></div><div class="summary-box">Loaded runtime: ${BUILD.runtime}\nCalendar events: ${calendarEvents().length}\nNext release candidate: Rules III Rebuild</div></article></div><article class="card"><h3>Vault inventory</h3><div class="list">${vaults().map(v=>`<div class="list-item"><span><strong>${esc(v.key)}</strong><br><small>${v.transactions} transactions • ${(v.bytes/1024).toFixed(0)} KB • ${esc(v.version)} • ${esc(v.status)}</small></span>${v.key===b?.key?'<span class="pill">best</span>':''}</div>`).join('')||'<p>No vault keys found.</p>'}</div></article></section>`;}
async function diagnostics(){const st=await swStatus(),b=bestVault(),gate=releaseGateReport(),tests=[['Runtime version',BUILD.version==='v99',BUILD.version],['Runtime proof valid',gate.checks.runtimeLoaded,shellProof().scriptNote],['No service worker registrations',st.registrations===0,`${st.registrations} registrations`],['No controller',!st.controller,st.controller?'controller active':'none'],['Calendar ICS available',calendarEvents().length>=0,`${calendarEvents().length} events`],['ICS contains VCALENDAR',makeICS().includes('BEGIN:VCALENDAR'),'ready'],['Support bundle excludes full rows',!JSON.stringify(exportBundle()).includes('"transactions":['),'no full transaction array in support bundle'],['Best vault present',!!(b&&b.transactions>0),b?`${b.transactions} transactions in ${b.key}`:'none found in this browser'],['No empty-vault autosave',true,'runtime reads best vault and does not save on boot'],['Roadmap count',ROADMAP.length===10,`${ROADMAP.length} releases`]];return`<section class="section active"><h2>Diagnostics Center</h2><article class="card"><h3>Runtime summary</h3><div class="summary-box">Release: ${BUILD.version} ${BUILD.name}\nLoaded runtime: ${BUILD.runtime}\nCache-bust: ${BUILD.cacheBust}\nDocument title: ${esc(document.title)}\nRuntime proof valid: ${gate.checks.runtimeLoaded?'yes':'warn'}\nScript proof note: ${esc(shellProof().scriptNote)}\nActive transactions: ${txs().length}\nBest vault transactions: ${b?.transactions??0}\nCalendar events: ${calendarEvents().length}\nService workers: ${st.registrations}\nController active: ${st.controller?'yes':'no'}\nCached Gringotts shells: ${st.caches.join(', ')||'none visible'}</div><div class="button-row"><button class="btn secondary" id="copyDebug2" type="button">Copy debug report</button><button class="btn secondary" id="downloadCalManifestDiag" type="button">Download calendar manifest</button><button class="btn secondary" id="downloadGateDiag" type="button">Download gate report</button><button class="btn secondary" id="downloadBackup2" type="button">Download backup</button><button class="btn secondary" id="openRescueDiag" type="button">Open rescue page</button></div></article><article class="card"><h3>Runtime self tests</h3><div class="list">${tests.map(r=>`<div class="list-item"><span><strong>${esc(r[0])}</strong><br><small>${esc(r[2])}</small></span><span class="pill">${r[1]?'PASS':'WARN'}</span></div>`).join('')}</div></article><article class="card"><h3>Safe localStorage inventory</h3><div class="table-wrap"><table><thead><tr><th>Key</th><th>Bytes</th><th>Parsed</th><th>Transactions</th><th>Rules</th></tr></thead><tbody>${storageInventory().map(x=>`<tr><td><code>${esc(x.key)}</code></td><td>${x.bytes}</td><td>${x.parsed?'yes':'no'}</td><td>${x.transactionCount??''}</td><td>${x.ruleCount??''}</td></tr>`).join('')}</tbody></table></div></article></section>`;}
function roadmap(){return`<section class="section active"><h2>Roadmap</h2><p>Exactly the next 10 planned releases after v99 Calendar ICS.</p><div class="roadmap">${ROADMAP.map(r=>`<div class="roadmap-item"><span class="pill">${esc(r[0])}</span><h3>${esc(r[1])}</h3><p>${esc(r[2])}</p></div>`).join('')}</div><article class="card"><h3>Restored / protected in v99</h3><div class="list">${RESTORED.map(x=>`<div class="list-item"><span><strong>${esc(x[0])}</strong><br><small>${esc(x[1])}</small></span><span class="pill">done</span></div>`).join('')}</div></article><article class="card"><h3>Still queued</h3><div class="list">${QUEUED.map(x=>`<div class="list-item"><span><strong>${esc(x[0])}</strong><br><small>${esc(x[1])}</small></span><span class="pill">queued</span></div>`).join('')}</div></article></section>`;}
async function render(){tabs();let html='';if(active==='dashboard')html=dashboard();else if(active==='ledger')html=ledger();else if(active==='planning')html=planning();else if(active==='calendar')html=calendarView();else if(active==='tools')html=tools();else if(active==='exports')html=exportsView();else if(active==='diagnostics')html=await diagnostics();else if(active==='roadmap')html=roadmap();$('main').innerHTML=html;bind();}
function bind(){const p=$('monthPrev');if(p)p.onclick=()=>{selectedMonth=addMonths(ensureMonth(),-1);localStorage.setItem('gringottsCleanMonth.v1',selectedMonth);render();};const n=$('monthNext');if(n)n.onclick=()=>{selectedMonth=addMonths(ensureMonth(),1);localStorage.setItem('gringottsCleanMonth.v1',selectedMonth);render();};const s=$('ledgerSearch');if(s)s.oninput=e=>{search=e.target.value;render();};const gc=$('goCalendar');if(gc)gc.onclick=()=>section('calendar');const gct=$('goCalendarTools');if(gct)gct.onclick=()=>section('calendar');const c=$('copyDebug2');if(c)c.onclick=copyDebug;const ct=$('copyDebugTools');if(ct)ct.onclick=copyDebug;const b=$('downloadBackup2');if(b)b.onclick=backup;const sb=$('safetyBackup');if(sb)sb.onclick=backup;const rb=$('restoreBtn');if(rb)rb.onclick=restoreBackup;const hf=$('helperFile');if(hf)hf.onchange=()=>{const f=hf.files?.[0];if(f)analyzeFile(f).catch(e=>toast('Helper failed: '+e.message));};const ch=$('copyHelper');if(ch)ch.onclick=copyHelper;const cs=$('copySummary');if(cs)cs.onclick=copySummary;const cse=$('copySummaryExport');if(cse)cse.onclick=copySummary;const ds=$('downloadSummary');if(ds)ds.onclick=()=>download('Gringotts_executive_summary_II.md',summaryMarkdown(),'text/markdown');const esm=$('exportSummaryMd');if(esm)esm.onclick=()=>download('Gringotts_executive_summary_II.md',summaryMarkdown(),'text/markdown');const di=$('downloadICS');if(di)di.onclick=()=>download('Gringotts_calendar_v99.ics',makeICS(),'text/calendar');const ei=$('exportICS');if(ei)ei.onclick=()=>download('Gringotts_calendar_v99.ics',makeICS(),'text/calendar');const ci=$('copyICS');if(ci)ci.onclick=copyICS;const cie=$('copyICSExport');if(cie)cie.onclick=copyICS;const dcm=$('downloadCalManifest');if(dcm)dcm.onclick=()=>downloadJSON('Gringotts_calendar_manifest_v99.json',calendarManifest());const ecm=$('exportCalManifest');if(ecm)ecm.onclick=()=>downloadJSON('Gringotts_calendar_manifest_v99.json',calendarManifest());const dcg=$('downloadCalManifestDiag');if(dcg)dcg.onclick=()=>downloadJSON('Gringotts_calendar_manifest_v99.json',calendarManifest());const emj=$('exportMonthlyJson');if(emj)emj.onclick=()=>downloadJSON('Gringotts_monthly_briefing_v99.json',monthlyBriefing());const epj=$('exportPlanningJson');if(epj)epj.onclick=()=>downloadJSON('Gringotts_planning_pack_v99.json',planningPack());const eh=$('exportHandoffJson');if(eh)eh.onclick=async()=>downloadJSON('Gringotts_debug_handoff_v99_no_ledger_rows.json',await supportHandoff());const dg=$('downloadGateDiag');if(dg)dg.onclick=()=>downloadJSON('Gringotts_release_gate_v99.json',releaseGateReport());const efb=$('exportFullBackup');if(efb)efb.onclick=backup;const sm=$('exportSmokeMd');if(sm)sm.onclick=()=>download('Gringotts_v99_smoke_test.md',smokeChecklist(),'text/markdown');const or=$('openRescue');if(or)or.onclick=()=>{location.href='rescue.html?from=v99tools';};const ord=$('openRescueDiag');if(ord)ord.onclick=()=>{location.href='rescue.html?from=v99diagnostics';};const ab=$('addBill');if(ab)ab.onclick=addBill;const ap=$('addPayday');if(ap)ap.onclick=addPayday;const ad=$('addDebt');if(ad)ad.onclick=addDebt;const apr=$('addPromo');if(apr)apr.onclick=addPromo;const se=$('saveExtra');if(se)se.onclick=saveExtra;const dec=$('addDecision');if(dec)dec.onclick=addDecision;const act=$('addAction');if(act)act.onclick=addAction;const cm=$('copyMeeting');if(cm)cm.onclick=copyMeeting;const dm=$('downloadMeeting');if(dm)dm.onclick=()=>download('Gringotts_meeting_pack.md',meetingMarkdown(),'text/markdown');document.querySelectorAll('[data-del-bill]').forEach(x=>x.onclick=()=>delBill(x.dataset.delBill));document.querySelectorAll('[data-del-pay]').forEach(x=>x.onclick=()=>delPay(x.dataset.delPay));document.querySelectorAll('[data-del-debt]').forEach(x=>x.onclick=()=>delDebt(x.dataset.delDebt));document.querySelectorAll('[data-del-promo]').forEach(x=>x.onclick=()=>delPromo(x.dataset.delPromo));document.querySelectorAll('[data-del-decision]').forEach(x=>x.onclick=()=>delDecision(x.dataset.delDecision));document.querySelectorAll('[data-del-action]').forEach(x=>x.onclick=()=>delAction(x.dataset.delAction));document.querySelectorAll('[data-toggle-action]').forEach(x=>x.onclick=()=>toggleAction(x.dataset.toggleAction));}
function addBill(){const d=cf();d.bills=d.bills||[];const name=$('billName').value.trim(),dueDate=$('billDueDate').value;if(!name){toast('Bill name needed');return;}if(!dueDate){toast('Due date needed');return;}d.bills.unshift({id:uid('bill'),name,amount:num($('billAmount').value),dueDate,active:true});saveCF(d);toast('Bill added');render();} function delBill(id){const d=cf();d.bills=(d.bills||[]).filter(x=>x.id!==id);saveCF(d);toast('Bill deleted');render();} function addPayday(){const d=cf();d.paydays=d.paydays||[];const name=$('payName').value.trim(),date=$('payDate').value;if(!name||!date){toast('Payday name and date needed');return;}d.paydays.unshift({id:uid('pay'),name,amount:num($('payAmount').value),date,repeat:true,active:true});saveCF(d);toast('Payday added');render();} function delPay(id){const d=cf();d.paydays=(d.paydays||[]).filter(x=>x.id!==id);saveCF(d);toast('Payday deleted');render();}
function addDebt(){const d=debtData();d.debts=d.debts||[];const name=$('debtName').value.trim();if(!name){toast('Debt name needed');return;}d.debts.unshift({id:uid('debt'),name,balance:num($('debtBalance').value),apr:num($('debtApr').value),minPayment:num($('debtMin').value)});saveDebt(d);toast('Debt added');render();} function delDebt(id){const d=debtData();d.debts=(d.debts||[]).filter(x=>x.id!==id);saveDebt(d);toast('Debt deleted');render();} function saveExtra(){const d=debtData();d.extraPayment=num($('extraPayment').value);saveDebt(d);toast('Extra payment saved');render();} function addPromo(){const p=promoData();p.cards=p.cards||[];const name=$('promoName').value.trim();if(!name){toast('Promo name needed');return;}p.cards.unshift({id:uid('promo'),name,balance:num($('promoBalance').value),promoEnd:$('promoEnd').value,regularApr:num($('promoRegular').value)});savePromo(p);toast('Promo added');render();} function delPromo(id){const p=promoData();p.cards=(p.cards||[]).filter(x=>x.id!==id);savePromo(p);toast('Promo deleted');render();}
function addDecision(){const m=meeting();m.decisions=m.decisions||[];const text=$('decisionText').value.trim();if(!text){toast('Decision text needed');return;}m.decisions.unshift({id:uid('decision'),text,at:new Date().toISOString()});saveMeeting(m);toast('Decision added');render();} function delDecision(id){const m=meeting();m.decisions=(m.decisions||[]).filter(x=>x.id!==id);saveMeeting(m);toast('Decision deleted');render();} function addAction(){const m=meeting();m.actions=m.actions||[];const text=$('actionText').value.trim();if(!text){toast('Action text needed');return;}m.actions.unshift({id:uid('action'),owner:$('actionOwner').value.trim()||'Household',text,done:false,at:new Date().toISOString()});saveMeeting(m);toast('Action added');render();} function toggleAction(id){const m=meeting();m.actions=(m.actions||[]).map(x=>x.id===id?{...x,done:!x.done}:x);saveMeeting(m);render();} function delAction(id){const m=meeting();m.actions=(m.actions||[]).filter(x=>x.id!==id);saveMeeting(m);toast('Action deleted');render();}
